test.config:
index test1
{
	type 			= rt
	path			= /test1
	rt_field = title
	rt_attr_uint	= tag
}

index test2 : test1
{
	path			= /test2
}

searchd
{

}

queries.sphinxql:
insert into test1 (id, title, tag) values (1,'test1 1 abc', 11),(2,'test1 2 abc', 12), (11,'test1 11 abc', 21), (12,'test1 12 abc', 22),(13,'test1 12 abc', 22),(14,'test1 12 abc', 22),(15,'test1 12 abc', 22), (16,'test1 12 abc',	22),(17,'test1 12 abc', 22),(18,'test1 12 abc', 22),(19,'test1 12 abc', 22),(20,'test2 12 abc', 22);
flush ramchunk test1;
show index test1 status like '%documents';
select count(*) from test1;
delete from test1 where id>12;
show index test1 status like '%documents';
select count(*) from test1;

show index test1 status like '%documents';
select count(*) from test1;


insert into test2 (id, title, tag) values (3, 'test2 abc', 13);
flush ramchunk test2;
show index test2 status like '%documents';
select count(*) from test2;
ATTACH TABLE test1 TO TABLE test2;
